arguments.prompt:
You are implementing a Blazor Web App for a recipe sharing community. The project has already been scaffolded at `/tmp/sv-129bee9d3b494c069b65dbdd6c09e3cb/RecipeCommunity` using `dotnet new blazor --interactivity Server`.

The project uses .NET 10 with Blazor's new rendering model (SSR by default, interactive Server where needed). The template already has `AddInteractiveServerComponents()` and `AddInteractiveServerRenderMode()` configured in Program.cs.

## Requirements
- Browse recipes by category — read-only content pages (SSR, no rendermode needed)
- Each recipe page has a star-rating widget (click to rate 1–5 stars) — needs `@rendermode InteractiveServer`
- A "Submit Recipe" page with a form (title, ingredients, steps) — needs `@rendermode InteractiveServer`
- Homepage displays recipe categories (static content, SSR)
- Most pages are read-only; only the rating widget and submit form need interactivity

## Architecture
- Use SSR (static server rendering) for read-only pages — do NOT add `@rendermode` to those pages
- Use `@rendermode InteractiveServer` ONLY on the interactive components (StarRating widget, SubmitRecipeForm)
- Create an in-memory recipe data service registered as a singleton

## Implementation Plan

### 1. Create Models (`Models/` directory under project root)

**Models/Recipe.cs**:
```csharp
namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string CategorySlug { get; set; } = "";
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public string Description { get; set; } = "";
    public int TotalRatingPoints { get; set; }
    public int RatingCount { get; set; }
    public double AverageRating => RatingCount > 0 ? (double)TotalRatingPoints / RatingCount : 0;
}
```

### 2. Create RecipeService (`Services/RecipeService.cs`)

```csharp
namespace RecipeCommunity.Services;

using RecipeCommunity.Models;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;
    private readonly Lock _lock = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", CategorySlug = "italian",
                Description = "A simple and delicious traditional Italian pizza with fresh mozzarella and basil.",
                Ingredients = new List<string> { "Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt" },
                Steps = new List<string> { "Preheat oven to 475°F (245°C).", "Roll out the pizza dough on a floured surface.", "Spread crushed tomatoes evenly over the dough.", "Tear mozzarella into pieces and distribute over the sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil leaves and a drizzle of olive oil." }
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", CategorySlug = "italian",
                Description = "Creamy Roman pasta made with eggs, pecorino cheese, and pancetta.",
                Ingredients = new List<string> { "Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper" },
                Steps = new List<string> { "Cook spaghetti in salted boiling water until al dente.", "Fry pancetta until crispy.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with pancetta.", "Remove from heat and stir in egg mixture quickly.", "Serve immediately with extra pecorino." }
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", CategorySlug = "indian",
                Description = "Tender chicken pieces in a creamy spiced tomato sauce.",
                Ingredients = new List<string> { "Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger" },
                Steps = new List<string> { "Marinate chicken in yogurt and spices for at least 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger until soft.", "Add tomato sauce and simmer for 15 minutes.", "Stir in cream and add the cooked chicken.", "Simmer for 10 more minutes and serve with rice." }
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian", CategorySlug = "asian",
                Description = "A vibrant stir-fried noodle dish with vegetables and a tangy sauce.",
                Ingredients = new List<string> { "Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar", "Garlic" },
                Steps = new List<string> { "Soak rice noodles in warm water for 20 minutes.", "Mix tamarind paste, fish sauce, and sugar for the sauce.", "Stir-fry tofu and garlic in a hot wok.", "Add noodles and sauce, tossing to combine.", "Add bean sprouts and cook for 1 minute.", "Serve topped with crushed peanuts and lime wedges." }
            },
            new Recipe
            {
                Id = 5, Title = "Guacamole", Category = "Mexican", CategorySlug = "mexican",
                Description = "Fresh and zesty avocado dip, perfect with tortilla chips.",
                Ingredients = new List<string> { "Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt" },
                Steps = new List<string> { "Halve and pit the avocados, scoop into a bowl.", "Mash to desired consistency.", "Stir in diced onion, tomato, jalapeño, and cilantro.", "Add lime juice and salt to taste.", "Serve immediately with tortilla chips." }
            },
            new Recipe
            {
                Id = 6, Title = "Beef Tacos", Category = "Mexican", CategorySlug = "mexican",
                Description = "Seasoned ground beef tacos with fresh toppings.",
                Ingredients = new List<string> { "Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning" },
                Steps = new List<string> { "Brown ground beef in a skillet over medium heat.", "Add taco seasoning and water, simmer until thickened.", "Warm taco shells in the oven.", "Fill shells with beef and top with lettuce, tomato, cheese, and sour cream.", "Serve with salsa on the side." }
            },
            new Recipe
            {
                Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
                Description = "Rich individual chocolate cakes with a molten center.",
                Ingredients = new List<string> { "Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract" },
                Steps = new List<string> { "Preheat oven to 425°F (220°C) and grease ramekins.", "Melt chocolate and butter together.", "Whisk in eggs, sugar, and vanilla.", "Fold in flour gently.", "Pour into ramekins and bake for 12-14 minutes.", "Invert onto plates and serve immediately." }
            }
        };
        _nextId = 8;
    }

    public List<(string Name, string Slug, int Count)> GetCategories()
    {
        lock (_lock)
        {
            return _recipes
                .GroupBy(r => new { r.Category, r.CategorySlug })
                .Select(g => (g.Key.Category, g.Key.CategorySlug, g.Count()))
                .OrderBy(c => c.Item1)
                .ToList();
        }
    }

    public List<Recipe> GetRecipesByCategory(string categorySlug)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
        }
    }

    public Recipe? GetRecipeById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe is not null && stars >= 1 && stars <= 5)
            {
                recipe.TotalRatingPoints += stars;
                recipe.RatingCount++;
            }
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        lock (_lock)
        {
            recipe.Id = _nextId++;
            _recipes.Add(recipe);
        }
    }
}
```

