    public List<(string Name, string Slug, int Count)> GetCategories()
    {
        lock (_lock)
        {
            return _recipes
                .GroupBy(r => new { r.Category, r.CategorySlug })
                .Select(g => (g.Key.Category, g.Key.CategorySlug, g.Count()))
                .OrderBy(c => c.Item1)
                .ToList();
        }
    }

    public List<Recipe> GetRecipesByCategory(string categorySlug)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
        }
    }

    public Recipe? GetRecipeById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe is not null && stars >= 1 && stars <= 5)
            {
                recipe.TotalRatingPoints += stars;
                recipe.RatingCount++;
            }
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        lock (_lock)
        {
            recipe.Id = _nextId++;
            _recipes.Add(recipe);
        }
    }
