            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", CategorySlug = "italian",
                Description = "Creamy Roman pasta made with eggs, pecorino cheese, and pancetta.",
                Ingredients = new List<string> { "Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper" },
                Steps = new List<string> { "Cook spaghetti in salted boiling water until al dente.", "Fry pancetta until crispy.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with pancetta.", "Remove from heat and stir in egg mixture quickly.", "Serve immediately with extra pecorino." }
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", CategorySlug = "indian",
                Description = "Tender chicken pieces in a creamy spiced tomato sauce.",
                Ingredients = new List<string> { "Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger" },
                Steps = new List<string> { "Marinate chicken in yogurt and spices for at least 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger until soft.", "Add tomato sauce and simmer for 15 minutes.", "Stir in cream and add the cooked chicken.", "Simmer for 10 more minutes and serve with rice." }
