                Steps = new List<string> { "Soak rice noodles in warm water for 20 minutes.", "Mix tamarind paste, fish sauce, and sugar for the sauce.", "Stir-fry tofu and garlic in a hot wok.", "Add noodles and sauce, tossing to combine.", "Add bean sprouts and cook for 1 minute.", "Serve topped with crushed peanuts and lime wedges." }
