@page "/categories"

<PageTitle>All Categories</PageTitle>

<h1>Recipe Categories</h1>
<p>Browse recipes by cuisine or type.</p>

<div class="row mt-3">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h4 class="card-title">@category.Name</h4>
                    <p class="text-muted">@category.Count recipe(s)</p>
                    <a href="categories/@category.Slug" class="btn btn-primary">View Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] public RecipeService RecipeService { get; set; } = default!;
}

@page "/categories/{Slug}"

<PageTitle>@(_categoryName) Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="categories">Categories</a></li>
        <li class="breadcrumb-item active">@_categoryName</li>
    </ol>
</nav>

<h1>@_categoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row mt-3">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        @if (recipe.RatingCount > 0)
                        {
                            <p class="text-warning mb-2">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    <span>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</span>
                                }
                                <small class="text-muted ms-1">(@recipe.RatingCount ratings)</small>
                            </p>
                        }
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string Slug { get; set; } = "";
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private List<Recipe> _recipes = new();
    private string _categoryName = "";

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(Slug);
        _categoryName = _recipes.FirstOrDefault()?.Category ?? Slug;
    }
}

@page "/recipe/{Id:int}"

@if (_recipe is null)
{
    <PageTitle>Recipe Not Found</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
    <a href="categories" class="btn btn-primary">Browse Categories</a>
}
else
{
    <PageTitle>@_recipe.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="categories">Categories</a></li>
            <li class="breadcrumb-item"><a href="categories/@_recipe.CategorySlug">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <h1>@_recipe.Title</h1>
    <p class="lead">@_recipe.Description</p>

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card shadow-sm mb-4">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in _recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>

            <div class="card shadow-sm">
                <div class="card-body">
                    <h6>Rate this Recipe</h6>
                    <StarRating RecipeId="@_recipe.Id" @rendermode="InteractiveServer" />
                </div>
            </div>
        </div>

        <div class="col-md-8">
            <h4>Instructions</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in _recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _hoveredStar ? "text-warning" : "text-muted")"
              role="button"
              @onmouseover="() => _hoveredStar = star"
              @onmouseout="() => _hoveredStar = 0"
              @onclick="() => SubmitRating(star)"
              style="font-size: 1.8rem; cursor: pointer;">
            @(star <= (_hoveredStar > 0 ? _hoveredStar : _selectedStar) ? "★" : "☆")
        </span>
    }
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-2 py-1 px-2" role="alert">
        Thanks! You rated this @_selectedStar star(s).
    </div>
}

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private int _hoveredStar;
    private int _selectedStar;
    private bool _submitted;

    private void SubmitRating(int stars)
    {
        _selectedStar = stars;
        RecipeService.AddRating(RecipeId, stars);
        _submitted = true;
    }
}

@rendermode InteractiveServer

@if (_submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Recipe Submitted!</h4>
        <p>Your recipe "<strong>@_model.Title</strong>" has been added to the @_model.Category category.</p>
        <a href="recipe/@_submittedId" class="btn btn-primary">View Recipe</a>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" />
            <ValidationMessage For="() => _model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Short Description</label>
            <InputTextArea id="description" class="form-control" rows="2" @bind-Value="_model.Description" />
            <ValidationMessage For="() => _model.Description" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="_model.IngredientsText" />
            <ValidationMessage For="() => _model.IngredientsText" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="_model.StepsText" />
            <ValidationMessage For="() => _model.StepsText" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel _model = new();
    private bool _submitted;
    private int _submittedId;

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            CategorySlug = _model.Category.ToLowerInvariant().Replace(" ", "-"),
            Description = _model.Description,
            Ingredients = _model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = _model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeService.AddRecipe(recipe);
        _submittedId = recipe.Id;
        _submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = "";

        public string Description { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient.")]
        public string IngredientsText { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step.")]
        public string StepsText { get; set; } = "";
    }
}

